class Solution:
    def lexicographicallySmallestArray(self, nums, limit):
        n = len(nums)
        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb

        for i in range(n):
            for j in range(i + 1, n):
                if abs(nums[i] - nums[j]) <= limit:
                    union(i, j)

        groups = {}
        for i in range(n):
            groups.setdefault(find(i), []).append(i)

        result = [0] * n
        for indices in groups.values():
            indices_sorted = sorted(indices)
            values_sorted = sorted(nums[t] for t in indices)
            for idx, val in zip(indices_sorted, values_sorted):
                result[idx] = val
        return result

