class Solution:
    def lexicographicallySmallestArray(self, nums, limit):
        n = len(nums)
        order = sorted(range(n), key=lambda i: nums[i])
        result = [0] * n
        i = 0
        while i < n:
            j = i
            while j + 1 < n and nums[order[j + 1]] - nums[order[j]] <= limit:
                j += 1
            group_indices = sorted(order[i:j + 1])
            group_values = [nums[order[t]] for t in range(i, j + 1)]
            for idx, val in zip(group_indices, group_values):
                result[idx] = val
            i = j + 1
        return result

