var lexicographicallySmallestArray = function(nums, limit) {
    const n = nums.length;
    const order = Array.from({ length: n }, (_, i) => i).sort((a, b) => nums[a] - nums[b]);
    const result = new Array(n);
    let i = 0;
    while (i < n) {
        let j = i;
        while (j + 1 < n && nums[order[j + 1]] - nums[order[j]] <= limit) {
            j++;
        }
        const groupIndices = order.slice(i, j + 1).sort((a, b) => a - b);
        const groupValues = [];
        for (let t = i; t <= j; t++) groupValues.push(nums[order[t]]);
        for (let g = 0; g < groupIndices.length; g++) {
            result[groupIndices[g]] = groupValues[g];
        }
        i = j + 1;
    }
    return result;
};
